223		VariableBits extract(uint64_t base, uint64_t width) const
224		{
225			if (is_chunk()) {
226				auto &chunk = as_chunk();
227				return VariableBits(VariableChunk{chunk.variable, chunk.base + base, width});
228			}
229			VariableBits ret;
230			for (uint64_t i = base, j = 0; j < width; i++, j++)
231				ret.append(as_bits()[i]);
232			return ret;
233		}
234	
235		void sort()
236		{
237			unpack();
238			auto &bits = as_bits();
239			std::sort(bits.begin(), bits.end());
240		}
241	
242		void sort_and_unify()
243		{
244			sort();
245			auto &bits = as_bits();
246			auto unified_end = std::unique(bits.begin(), bits.end());
247			bits.erase(unified_end, bits.end());
248		}
249	
250		bool has_dummy_bits() const
251		{
252			if (is_chunk())
253				return as_chunk().variable.kind == Variable::Dummy;
254			for (auto chunk : chunks()) {
255				if (chunk.variable.kind == Variable::Dummy)
256					return true;
257			}
258			return false;
259		}
260	
261		bool has_special_nets();
262	
263		class const_bit_iterator
264		{
265			const VariableBits *container;
266			int index;
267	
268		public:
269			using iterator_category = std::random_access_iterator_tag;
270			using value_type = VariableBit;
271			using difference_type = int;
272	
273			const_bit_iterator(const VariableBits *container, int index)
274				: container(container), index(index)
275			{}
276			VariableBit operator*() const { return (*container)[index]; }
277			const_bit_iterator &operator++()
278			{
279				index++;
280				return *this;
281			}
282			const_bit_iterator operator++(int)
283			{
284				auto tmp = *this;
285				index++;
286				return tmp;
287			}
288			const_bit_iterator &operator--()
289			{
290				index--;
291				return *this;
292			}
293			const_bit_iterator operator+(int n) const { return {container, index + n}; }
294			const_bit_iterator operator-(int n) const { return {container, index - n}; }
295			int operator-(const const_bit_iterator &other) const { return index - other.index; }
296			auto operator<=>(const const_bit_iterator &other) const { return index <=> other.index; }
297			bool operator==(const const_bit_iterator &other) const = default;
298		};
299	
300		const_bit_iterator begin() const { return const_bit_iterator(this, 0); }
301		const_bit_iterator end() const { return const_bit_iterator(this, bitwidth()); }
302	
303		class iterator_base
304		{
305		protected:
306			const VariableBits &container;
307			uint64_t offset;
308			VariableChunk chunk;
309	
310			void incr()
311			{
312				offset += chunk.length;
313				if (offset < container.bitwidth()) {
314					log_assert(!container.is_chunk());
315					auto &bits = container.as_bits();
316					chunk = {bits[offset].variable, bits[offset].offset, 1};
317					fixup_chunk();
318				}
319			}
320	
321		public:
322			using iterator_category = std::input_iterator_tag;
323	
324			iterator_base(const VariableBits &container, uint64_t offset)
325				: container(container), offset(offset)
326			{
327				if (offset < container.bitwidth()) {
328					if (container.is_chunk()) {
329						chunk = container.as_chunk();
330					} else {
331						auto &bits = container.as_bits();
332						chunk = {bits[offset].variable, bits[offset].offset, 1};
333						fixup_chunk();
334					}
335				}
336			}
337	
338			void fixup_chunk()
339			{
340				auto &bits = container.as_bits();
341				while (offset + chunk.length < bits.size() &&
342						bits[offset + chunk.length].variable == chunk.variable &&
343						bits[offset + chunk.length].offset == chunk.base + chunk.length) {
344					chunk.length++;
345				}
346			}
347	
348			bool operator==(const iterator_base &other) const { return offset == other.offset; }
349			bool operator!=(const iterator_base &other) const { return !(*this == other); }
350		};
351	
352		class chunk_iterator : public iterator_base
353		{
354		public:
355			using value_type = VariableChunk;
356			chunk_iterator(const VariableBits &bits, uint64_t offset) : iterator_base(bits, offset) {}
357			VariableChunk operator*() const { return chunk; }
358			chunk_iterator &operator++()
