29	
30	namespace slang_frontend {
31	
32	class DiagnosticIssuer;
33	struct InferredMemoryDetector : public TimingPatternInterpretor,
34									public ast::ASTVisitor<InferredMemoryDetector,
35											ast::VisitFlags::Statements | ast::VisitFlags::Expressions>,
36									public DiagnosticIssuer
37	{
38		Yosys::pool<const ast::Symbol *> memory_candidates;
39		std::function<bool(const ast::InstanceSymbol &sym)> should_dissolve;
40		bool disallow_implicit = false;
41	
42		InferredMemoryDetector(SynthesisSettings &settings,
43				std::function<bool(const ast::InstanceSymbol &sym)> should_dissolve,
44				EvalContext &evalCtx)
45			: TimingPatternInterpretor(settings, (DiagnosticIssuer &)*this, evalCtx),
46			  should_dissolve(should_dissolve),
47			  disallow_implicit(settings.no_implicit_memories.value_or(false))
48		{}
49	
50		void process(const ast::Symbol &root)
51		{
52			auto first_pass = ast::makeVisitor(
53					[&](auto &, const ast::VariableSymbol &symbol) {
54						if (symbol.lifetime == ast::VariableLifetime::Static &&
55								symbol.getType().isUnpackedArray() &&
56								symbol.getType().hasFixedRange() &&
57								(!disallow_implicit || find_user_hint(symbol)) &&
58								symbol.getParentScope()->getContainingInstance() &&
59								symbol.getParentScope()
60										->getContainingInstance()
61										->parentInstance->isModule() &&
62								symbol.kind != ast::SymbolKind::FormalArgument)
63							memory_candidates.insert(&symbol);
64					},
65					[&](auto &visitor, const ast::GenerateBlockSymbol &symbol) {
66						if (symbol.isUninstantiated)
67							return;
68						visitor.visitDefault(symbol);
69					},
70					[&](auto &visitor, const ast::InstanceSymbol &symbol) {
71						if (should_dissolve(symbol))
72							visitor.visitDefault(symbol);
73					});
74			root.visit(first_pass);
75			root.visit(*this);
76		}
77	
78		struct LHSVisitor : public ast::ASTVisitor<LHSVisitor,
79									ast::VisitFlags::Statements | ast::VisitFlags::Expressions>
80		{
81			InferredMemoryDetector &rhs;
82			LHSVisitor(InferredMemoryDetector &rhs) : rhs(rhs) {}
83	
84			void handle(const ast::ElementSelectExpression &expr)
85			{
86				expr.value().visit(*this);
87				expr.selector().visit(rhs);
88			}
89	
90			void handle(const ast::RangeSelectExpression &expr)
91			{
92				expr.value().visit(*this);
93				expr.left().visit(rhs);
94				expr.right().visit(rhs);
95			}
96	
97			void handle(const ast::ValueExpressionBase &expr)
98			{
99				rhs.disqualify(expr.symbol, expr.sourceRange.start());
100			}
101		};
102	
103		std::optional<std::string_view> find_user_hint(const ast::Symbol &symbol)
104		{
105			const static std::set<std::string> recognized = {"ram_block", "rom_block", "ram_style",
106					"rom_style", "ramstyle", "romstyle", "syn_ramstyle", "syn_romstyle"};
107	
108			for (auto attr : global_compilation->getAttributes(symbol)) {
109				if (recognized.count(std::string{attr->name}) && !attr->getValue().isFalse())
110					return attr->name;
111			}
112			return {};
113		}
114	
115		void disqualify(const ast::Symbol &symbol, slang::SourceLocation loc)
116		{
117			std::optional<std::string_view> found_attr;
118			if (memory_candidates.count(&symbol) && (found_attr = find_user_hint(symbol))) {
119				auto &diag = add_diag(diag::MemoryNotInferred, symbol.location);
120				diag << found_attr.value();
121				diag.addNote(diag::NoteUsageBlame, loc);
