146		void handle(const ast::ElementSelectExpression &expr)
147		{
148			if (ast::ValueExpressionBase::isKind(expr.value().kind)) {
149				// do nothing
150			} else {
151				expr.value().visit(*this);
152			}
153	
154			expr.selector().visit(*this);
155		}
156	
157		bool wr_allowed = false;
158	
159		void handle(const ast::ExpressionStatement &stmt)
160		{
161			if (stmt.expr.kind == ast::ExpressionKind::Assignment &&
162					stmt.expr.as<ast::AssignmentExpression>().isNonBlocking() && wr_allowed) {
163				auto &assign = stmt.expr.as<ast::AssignmentExpression>();
164				assign.right().visit(*this);
165	
166				const ast::Expression *raw_lexpr = &assign.left();
167				LHSVisitor fallback(*this);
168				while (true) {
169					switch (raw_lexpr->kind) {
170					case ast::ExpressionKind::RangeSelect: {
171						auto &sel = raw_lexpr->as<ast::RangeSelectExpression>();
172						sel.left().visit(*this);
173						sel.right().visit(*this);
174						raw_lexpr = &sel.value();
175					} break;
176					case ast::ExpressionKind::ElementSelect: {
177						auto &sel = raw_lexpr->as<ast::ElementSelectExpression>();
