179						raw_lexpr = &sel.value();
180						if (ast::ValueExpressionBase::isKind(sel.value().kind)) {
181							// a potential memory candidate
182							return;
183						}
184					} break;
185					case ast::ExpressionKind::MemberAccess: {
186						const auto &acc = raw_lexpr->as<ast::MemberAccessExpression>();
187						raw_lexpr = &acc.value();
188					} break;
189					default: raw_lexpr->visit(fallback); return;
190					}
191				}
192	
193				log_abort(); // unreachable
194			}
195	
196			stmt.expr.visit(*this);
197		}
